import{_ as r,o,c as a,ak as e}from"./chunks/framework.oFDsBAuP.js";const s="/settings/topup/wallet-overview.png",n="/settings/topup/wallet-redeem.png",l="/settings/topup/wallet-invite.png",m=JSON.parse('{"title":"钱包管理","description":"","frontmatter":{"title":"钱包管理"},"headers":[],"relativePath":"settings/user/topup.md","filePath":"settings/user/topup.md"}'),i={name:"settings/user/topup.md"};function p(g,t,h,c,_,d){return o(),a("div",null,[...t[0]||(t[0]=[e('<h2 id="钱包管理" tabindex="-1">钱包管理 <a class="header-anchor" href="#钱包管理" aria-label="Permalink to &quot;钱包管理&quot;">​</a></h2><p>配额是平台内部计费单位，消耗量与模型倍率、调用量等相关。左侧导航进入「<strong>钱包管理</strong>」，或直接访问 <a href="https://console.atomflow.org/console/topup" target="_blank" rel="noreferrer">控制台 · 钱包管理</a>。</p><p><img src="'+s+'" alt="钱包管理：账户充值与邀请奖励"></p><p>页面通常分为 <strong>账户充值</strong>（在线支付、额度选择、兑换码）与 <strong>邀请奖励</strong>（邀请链接、收益划转）等板块。支持的方式以控制台实际展示为准（例如支付宝、Stripe 等）。</p><h3 id="选择充值金额并完成支付" tabindex="-1"><a href="#选择充值金额并完成支付">选择充值金额并完成支付</a> <a class="header-anchor" href="#选择充值金额并完成支付" aria-label="Permalink to &quot;[选择充值金额并完成支付](#选择充值金额并完成支付)&quot;">​</a></h3><ol><li>在 <strong>账户充值</strong> 中查看当前余额、历史消耗等统计。</li><li>填写或选择 <strong>充值数量</strong>，并选择 <strong>支付方式</strong>（如支付宝、Stripe）。</li><li>可在 <strong>选择充值额度</strong> 中点击预设档位快速填入。</li><li>确认 <strong>实付金额</strong> 后按页面提示发起支付，在支付渠道完成付款；返回后余额会更新。需要核对流水时，可点击「<strong>账单</strong>」查看。</li></ol><h3 id="输入兑换码" tabindex="-1"><a href="#输入兑换码">输入兑换码</a> <a class="header-anchor" href="#输入兑换码" aria-label="Permalink to &quot;[输入兑换码](#输入兑换码)&quot;">​</a></h3><ol><li>在同一页的 <strong>兑换码充值</strong> 区域找到输入框。</li><li>粘贴或输入管理员提供的兑换码。</li></ol><p><img src="'+n+'" alt="兑换码充值区域"></p><h3 id="完成兑换" tabindex="-1"><a href="#完成兑换">完成兑换</a> <a class="header-anchor" href="#完成兑换" aria-label="Permalink to &quot;[完成兑换](#完成兑换)&quot;">​</a></h3><ol><li>点击「<strong>兑换额度</strong>」按钮，系统校验兑换码。</li><li>兑换成功后按提示确认到账，余额同步更新。</li></ol><h3 id="邀请奖励" tabindex="-1"><a href="#邀请奖励">邀请奖励</a> <a class="header-anchor" href="#邀请奖励" aria-label="Permalink to &quot;[邀请奖励](#邀请奖励)&quot;">​</a></h3><p>每个账号有专属邀请链接。被邀请用户注册并产生充值等行为后，你可按平台规则获得奖励；在 <strong>邀请奖励</strong> 中可查看待使用收益、总收益与邀请人数，将奖励 <strong>划转到余额</strong> 后即可用于消费。可复制邀请链接分享给好友。</p><p><img src="'+l+'" alt="邀请奖励：收益统计与邀请链接"></p><p>奖励细则与比例以页面「奖励说明」及运营政策为准。</p>',15)])])}const f=r(i,[["render",p]]);export{m as __pageData,f as default};
